<template>
  <div class="d-flex justify-content-center p-2">
    <div class="col-9 justify-content-center">
      <b-card ref="cart" v-if="getTotal != 0" class="w-100" header-tag="header">
        <div
          class="col-md col-sm"
          style="border: none"
          v-for="(getProductInCart, index) of getProductsInCart"
          :key="index"
        >
          <CartItem v-bind:product="getProductInCart" />
        </div>
      </b-card>
    </div>
    <!--  -->
    <div class="col-md-3 col-sm p-3">
      <div class="card">
        <ul class="list-group list-group-flush">
          <li class="list-group-item" style="border: none">
            Subtotal
            <span class="badge badge-light float-right">R{{ subtotal }}</span>
          </li>
          <li class="list-group-item" style="border: none">
            VAT
            <span class="badge badge-light float-right">14%</span>
          </li>
          <li class="list-group-item" style="border: none">
            Total
            <span class="badge badge-light float-right">R{{ getTotal }}</span>
          </li>
        </ul>
      </div>

      <!-- eslint-disable no-irregular-whitespace -->
      <form
        v-if="userLoggedIn == true && getTotal != 0"
        action="https://sandbox.payfast.co.za​/eng/process"
        method="post"
      >
        <input type="hidden" name="merchant_id" value="10000100" />
        <input type="hidden" name="merchant_key" value="46f0cd694581a" />
        <input
          type="hidden"
          name="return_url"
          value="https://laudelam.github.io/#/payment"
        />
        <input
          type="hidden"
          name="cancel_url"
          value="https://laudelam.github.io/#/products"
        />
        <input type="hidden" name="amount" v-model="getTotal" />
        <input type="hidden" name="item_name" v-model="getOrderNumber" />
        <button
          type="submit"
          @click="setOrder()"
          class="btn btn-secondary btn-sm btn-block mt-2 shadow-none"
        >
          Pay Now
        </button>
      </form>

      <button
        v-else
        v-on:click="checkoutProduct"
        type="submit"
        class="btn btn-secondary btn-sm btn-block mt-2 shadow-none"
      >
        Pay Now
      </button>
    </div>
  </div>
</template>

<script>
import CartItem from "../components/CartItem.vue";
import Swal from "sweetalert2";
import CryptoJS from "crypto-js";

const Toast = Swal.mixin({
  toast: true,
  position: "center",
  showConfirmButton: false,
  timerProgressBar: true,
  didOpen: (toast) => {
    toast.addEventListener("mouseenter", Swal.stopTimer);
    toast.addEventListener("mouseleave", Swal.resumeTimer);
  },
});

export default {
  components: {
    CartItem,
  },

  data() {
    return {
      products: [],
      userOrder: {},
    };
  },

  computed: {
    getProductsInCart() {
      return this.$store.getters.productsInCart;
    },

    userLoggedIn() {
      return this.$store.getters.isLoggedIn;
    },

    getUser() {
      return this.$store.getters.getUser;
    },

    subtotal() {
      return this.roundToTwo(this.$store.getters.subtotal);
    },

    getTotal() {
      let total = this.roundToTwo(this.$store.getters.total);
      return total;
    },

    getOrders() {
      return this.$store.getters.getOrders;
    },

    getOrderNumber() {
      let orderNum = null;
      let number = Date.now().toString();
      // pad with extra random digit
      number += number + Math.floor(Math.random() * 10);
      // format
      orderNum = [number.slice(0, 4), number.slice(4, 10)].join("-");
      return orderNum;
    },
  },

  methods: {
    roundToTwo(num) {
      return +(Math.round(num + "e+2") + "e-2");
    },

    //
    checkoutProduct() {
      if (this.userLoggedIn != true) {
        Toast.fire({
          icon: "info",
          title: "Please Login or Sign up",
          showConfirmButton: true,
        }).then(() => {
          this.$router.push("/login");
        });
      }
    },

    //Create order
    setOrder() {
      if (this.isLoggedIn == true || this.getTotal != 0) {
        let user = this.getUser.email;
        let orderNum = this.getOrderNumber;
        let productsPerOrder = this.getProductsInCart;
        let total = this.getTotal;
        let today = new Date();
        let currentDate =
          today.getFullYear() + "-" + (today.getMonth() + 1) + "-" + today.getDate();

        let newOrder = {
          orderNumber: orderNum,
          user: user,
          productsPerOrder: productsPerOrder,
          total: total,
          date: currentDate,
        };

        this.getSignature(orderNum, total);
        this.$store.commit("clearCart");
        // this.$store.commit("emptyOrders");

        // this.$store.commit("setProductsPerOrder", newOrder);
        return (this.userOrder = newOrder);
      }
    },

    //Generate signature for transaction security
    getSignature(orderNum, total) {
      if (this.isLoggedIn == true || this.getTotal != 0) {
        const generateMD5 = (obj, secret = "secret") => {
          let str = "";
          for (let val in obj) {
            str += obj[val];
          }
          str += secret;
          return CryptoJS.MD5(str).toString();
        };

        let data = {
          //merchant details
          merchant_id: "10000100",
          merchant_key: "46f0cd694581a",
          return_url: "https://laudelam.github.io/#/payment",
          cancel_url: "https://laudelam.github.io/#/products",
          //transaction details
          amount: total,
          item_name: orderNum,
        };

        let signature = generateMD5(data);
        return signature;
      }
    },
  },
};
</script>

<style scoped>
.list-group-item1 {
  list-style-type: none;
}
</style>
