//Get user logged in
const getUser = store.getters.getUser;
const isLoggedIn = store.getters.isLoggedIn;
const getProducts = store.getters.productsInCart;
const getOrders = store.getters.getOrders;

//Creates cart for user if not existant and adds products to the cart 
export const updateCartDB = async () => {
  if (isLoggedIn == true) {
    try {
      let cartCollection = await db.collection("carts");
      cartCollection = await cartCollection.where("user", "==", getUser.email)
      let query = await cartCollection.get();

      if(!query.empty){
        query.docs.forEach(async (doc)=>{
          cartCollection = await db.collection("carts")
          if(getProducts.length == 0){
            cartCollection.doc(doc.id).delete()
            // console.log("Cart deleted");
          }else{
            cartCollection.doc(doc.id).update({
              "products": getProducts
          })
          }
        })
      }else{
        cartCollection = await db.collection("carts")
        let cart = {user: getUser.email, products: getProducts}
        // console.log("Cart:", cart);
        await cartCollection.add(cart)
      }
    } catch (e) {
      console.log(e);
    }
  }
};

