//Clearing User Cart
export const clearUserCart = async () => {
  try {
    let cartCollection = await db.collection("carts");
    cartCollection = await cartCollection.where("user", "==", getUser.email)
    let query = await cartCollection.get();

    if(!query.empty){
      query.docs.forEach(async (doc)=>{
        cartCollection = await db.collection("carts")
        cartCollection.doc(doc.id).delete()
      })
    }
  } catch (e) {
    console.log(e);
  }
};

//Update products in cart from DB once user logs in
export const updateStoreFromDB = async () => {
  let cartCollection = await db.collection("carts");
  cartCollection = await cartCollection.where("user", "==", getUser.email)
  let query = await cartCollection.get();
  let products = []

  if(!query.empty){
    query.docs.forEach(async (doc)=>{
      products = doc.data().products
    })
    if (products.length > 0) {
      store.commit("cartProductsList", products);
    }else if(products.length == 0 && getProducts.length != 0){
      query.docs.forEach(async (doc)=>{
        cartCollection = await db.collection("carts")
        cartCollection.doc(doc.id).update({
            "products": getProducts
        })
      })
    }
  }
};

//Update orders in DB
export const updateOrders = async () => {
  if (isLoggedIn == true) {
    for (let i = 0; i < getOrders.length; i++) {
      let ordersCollection = await db
        .collection("orders")
        .doc(getOrders[i].orderNumber);
      let doc = await ordersCollection.get();
      let order = null;

      if (!doc.exists) {
        // If user exists
        try {
          order = {
            orderNumber: getOrders[i].orderNumber,
            user: getUser.email,
            productsPerOrder: getOrders[i].productsPerOrder,
            total: getOrders[i].total,
            date: getOrders[i].date,
          };
          console.log("Order:", order);
          ordersCollection.set(order);
        } catch (e) {
          console.log(e);
        }
      }
    }
  }
};

//Fetch user orders
export const fetchOrders = async () => {
  if (isLoggedIn == true) {
    let ordersCollection = db.collection("orders");
    ordersCollection = await ordersCollection.where(
      "user",
      "==",
      getUser.email
    );
    let query = await ordersCollection.get();
    let orders = [];

    query.docs.forEach((doc) => {
      let order = doc.data();
      orders.push(order);
    });
    orders = orders.reverse();
    return orders;
  }
};

//Fetch one order per request of order number
export const fetchOrder = async (orderNum) => {
  let ordersCollection = await db.collection("orders").doc(orderNum);
  let doc = await ordersCollection.get();

  if (doc.exists) {
    let order = doc.data();
    // this.$store.commit("emptyOrders");
    return order;
  }
};

